import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life - Next Generation", () => {
  it.todo("should return empty array for empty input");
  it.todo("should kill a single live cell (underpopulation)");
  it.todo("should kill two adjacent live cells (underpopulation)");
  it.todo("should keep a live cell alive with 3 neighbors (survival)");
  it.todo("should kill a live cell with more than 3 neighbors (overpopulation)");
  it.todo("should bring a dead cell to life with exactly 3 neighbors (reproduction)");
  it.todo("should oscillate a vertical blinker into a horizontal blinker");
  it.todo("should keep a 2x2 block as a still life");
  it.todo("should handle cells with negative coordinates");
});
